  ('police-b20a8cf8-moex-00344', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '近日，金融詐欺或電信詐騙案件頻傳，警察辦理涉及帳戶匯款詐欺案件過程中，有關設定警示帳 戶及啟動金融機構聯防機制等措施，以下敘述何者正確？', '["受詐騙民眾親到金融機構告知遭受詐騙時，警察機關應於四小時內派員到場受理民眾報案", "金融機構協助受詐騙民眾就疑似受詐帳戶圈存或止扣時，警察機關於二十四小時內未通知列為 警示時可逕予解除", "警察機關通報銀行將存款帳戶列為警示時，原則以書面公文行之並至遲於三日內送達", "警察機關通報銀行將存款帳戶列為警示時，其警示期限逾一年自動失其效力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00345', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '證人保護法規定，證人到場作證，致生命、身體、自由或財產有遭受危害之虞，而有受保護之必 要者，於案件偵查中，應由何人核發證人保護書？', '["司法警察官", "法官", "檢察官", "檢察事務官"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00346', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '依警察偵查犯罪手冊規定，境外犯罪案件，應以被害人工作地、現住地、家屬現住地等因素，決 定管轄之警察機關，請問前開因素之次序為何？', '["被害人之工作地、現住地、家屬現住地", "被害人之現住地、工作地、家屬現住地", "家屬現住地、被害人之現住地、工作地", "家屬現住地、被害人之工作地、現住地"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00347', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '犯罪現場應依任務需要，可將現有人員區分為調查組及勘察組，下列何者不是勘察組之任務？', '["運用科學技術與方法勘察採證", "採集各類跡證", "訪問被害人", "研判犯罪嫌疑人之入出口、方法及關聯性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00348', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '司法警察官處理刑案時，應關懷協助被害人及家屬，採取被害保護作為，下列關於司法警察官對 被害保護作為之敘述，何者錯誤？', '["被害人未受傷案件，應安撫被害人情緒，協助報案", "被害人受傷案件，應儘速協助及護送就醫", "如被害人因傷住院，應以警車送被害人到警察機關接受詢問", "為保護被害人家屬隱私，得依其要求，適當隔離媒體"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00349', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '警察機關逮捕違反何犯罪處以刑事處罰之通緝犯，應於製作筆錄時，詢問被告或犯罪嫌疑人有無 監護或照顧未滿十二歲子女或兒童之情形，並調閱戶役政資料比對檢核，遇有兒童及少年福利與 權益保障法第53條第1項各款或第54條之情事者，應依各該條規定，通報直轄市、縣（市）主 管機關？', '["竊盜罪", "強盜罪", "詐欺罪", "毒品危害防制條例之罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00350', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '下列關於偵查中辯護人權限之說明，何者錯誤：', '["得於司法警察官或司法警察詢問犯罪嫌疑人時在場", "偵查中辯護人得陳述意見", "偵查中司法警察官詢問時，辯護人得檢閱卷宗及證物", "偵查中辯護人於司法警察官詢問犯罪嫌疑人時得手寫方式札記詢問要點"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00351', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '刑案紀錄資料應於受理刑案發生或破獲移送之時起，多久時間內填輸，不得虛報、匿報或遲報：', '["12小時", "24小時", "36小時", "48小時"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00352', 'police-b20a8cf8', 'police-b20a8cf8-moex-112-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '下列關於家庭暴力案件之說明，何者錯誤？', '["民事保護令分為通常保護令、暫時保護令與緊急保護令", "司法警察發現家庭暴力罪之現行犯，應報請檢察官核發拘票後，始得逮捕", "司法警察偵查犯罪認犯罪嫌疑人犯家庭暴力罪嫌疑重大，且有繼續侵害家庭成員生命、身體或 自由之危險，而情況急迫者，得逕行拘提之", "警察機關於詢問家庭暴力案件被害人時，得採取適當之保護及隔離措施"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:23+00:00", "source_pdf_sha1": "6d31b0ab7297", "answer_pdf_sha1": "5170d7076e3d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "503", "s": "1403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
